import React, { useEffect } from 'react';
import { Link } from 'react-router-dom';
import {Swiper,SwiperSlide} from 'swiper/react'
import { Autoplay } from 'swiper/modules'

const InfiniteRunningImages = ({ images, directionRight }) => {
   const breakpoints = {
      320: {
         slidesPerView: 1.5,
      },
      479: {
         slidesPerView: 2,
      },
      768: {
         slidesPerView: 2.5,
      },
      992: {
         slidesPerView: 3.2,
      },
      1200: {
         slidesPerView: 4.2,
      }
   }
  return (
    <div className='works__wrapper'>
       <Swiper
            modules={[Autoplay]}
            direction='horizontal'
            slidesPerView={3.7} // Display 4.5 slides per view
            loop={true}
            allowTouchMove={false} 
            breakpoints={breakpoints}
            autoplay={{
              delay: 1, // Set delay to 1 millisecond
              disableOnInteraction: false,
              reverseDirection: directionRight,
            }}

            speed={5000} // Large value for smooth continuous movement
            spaceBetween={24} // Adjust as needed
            >
         {
            images.map((item,i)=>{
               return <SwiperSlide key={i}>
               <Link className='works__link -ibg' to={item.link}>
                 <img
                   src={item.image}
                   alt='picture'
                 />
               </Link>
               </SwiperSlide>
            })
         }
         </Swiper>
    </div>
  );
};

export default InfiniteRunningImages;
