import React, { useState, useRef, useEffect } from 'react';
import gsap from "gsap";
import { useGSAP } from '@gsap/react';

import { BrowserRouter, Route, Routes } from 'react-router-dom';
import Home from './Components/pages/home/Home';
import Header from './Components/Header/Header';
import Footer from './Components/General/Footer';
import MyContextProvider from './Components/General/MyContextProvider';
import Notfound from './Components/General/Notfound';
import './css/style.css';

const App = () => {
   const [isHovered, setIsHovered] = useState(false);

   const xTo = useRef();
   const yTo = useRef();
   const app = useRef();
  
   const { context, contextSafe } =  useGSAP(() => {
     xTo.current = gsap.quickTo(".flair", "x", {duration: 0.1, ease: "power3"});
     yTo.current = gsap.quickTo(".flair", "y", {duration: 0.1, ease: "power3"});
   }, { scope: app });

   const moveShape = contextSafe((e) => {
     xTo.current(e.clientX);
     yTo.current(e.clientY);
   });
   
  return (
    <div className="App" ref={app} onMouseMove={(e) => moveShape(e)}>
      <MyContextProvider>
        <BrowserRouter>
          <div className="wrapper">
         <div className={isHovered ? "flair active" : "flair"}><span>View <br />project</span></div>
            <Header />
            <Routes>
              <Route element={<Home isHovered={isHovered} setIsHovered={setIsHovered}/>} path="/" />
              <Route path="*" element={<Notfound />} />
            </Routes>
            <Footer />
          </div>
        </BrowserRouter>
      </MyContextProvider>
    </div>
  );
};

export default App;
