import React from 'react'
import logo from '../../img/icons/logo1.png'
import { Link, NavLink } from 'react-router-dom'
import { Menu, rights, Privicylist } from '../General/Generalinfo'; 
import { IoArrowForward } from "react-icons/io5";
import { IoIosArrowUp } from "react-icons/io";

import { useState } from 'react';
import Media from '../General/Media';
import Letstalk from '../General/Letstalk';


export default function Header() {
   const [burgerActive, setBurgerActive] = useState(false)
   const [subMenu, setSubMenu] = useState(false)

   const workCount = 5

   const burgerHandle = ()=>{
      setBurgerActive(!burgerActive)
   }
   const subMenuHandle = ()=>{
      setSubMenu(!subMenu)
   }
  return (
   <header className="header">
         <div className='header__top'>
            <div className='top__container'>
               <Link to='/' className='header__logo'><img src={logo} alt="logo" /></Link>
               <Letstalk />
               <button onClick={burgerHandle} type="button" className={burgerActive ? 'burger__icon icon-burger menu-open' : 'burger__icon icon-burger'}><span></span></button>
            </div>
         </div>

         <nav className="header__menu menu">
         <ul className="menu__list">
            {
               Menu.map((item,i)=>{
                  return i !== 5 ? <li className='menu__item' key={i}><a className='menu__link' href={'#'+item}><span className='menu__link_text'>{item}</span>{item === 'Work' ? <span className='work-count'>{workCount}</span> : false}</a></li> : false
               })
            }
         </ul>
      </nav>
      <div className={burgerActive ? 'burger-body _active-burger' : 'burger-body'}>
         <div className='burger-body__block'>
            <nav className="burger-body__menu menu">
               <ul className="menu__list">
               {
                  Menu.map((item,i)=>{
                     return i !== 5 ? <li className='menu__item' key={i}><a className='menu__link' onClick={()=>{setBurgerActive(!burgerActive)}} href={'#'+item}>{item}{item === 'Work' ? <span className='work-count'>{workCount}</span> : false}</a></li> : 
                     <li className='menu__item' key={i}>
                        <button onClick={subMenuHandle} className={subMenu ? 'menu__link _active' : 'menu__link'} to={item}>
                           <span>{item}</span>
                           <IoIosArrowUp style={{rotate: subMenu ? '180deg' : ''}}/>
                        </button>
                        <ul className='sub-menu'>
                           {
                              Privicylist.map((item,i)=>{
                                 return <li style={{display: subMenu ? 'block' : 'none'}} key={i} className="sub-menu__item"><Link to='' className='sub-menu__link menu__link'>{item}</Link></li>
                              })
                           }
                           
                        </ul>
                     </li>
                  })
               }
               </ul>
            </nav>
            <div className="burger-body__bottom">
               <Media />
               <div className="burger-body__rights">{rights}</div>
            </div>
         </div>
      </div>
   </header>
  )
}
