import React, { useEffect, useRef } from 'react';
import 'odometer/themes/odometer-theme-default.css';
import Odometer from 'odometer';
import { preLoaderAnim } from './Preloaderanim';

const OdometerAnimation = () => {
  const odometerRef = useRef(null);

  useEffect(() => {
    // Initialize odometer when component mounts
    preLoaderAnim()
    const odometer = new Odometer({
      el: odometerRef.current,
      value: '000', // Initial value
      duration: 10000, // Animation duration in milliseconds
      format: '(,ddd)', // Format for thousands separator
    });

    // Animate from 0 to 100 after 2 seconds (2000 milliseconds)
    setTimeout(() => {
      odometer.update(100);
      // Allow scrolling after 3 seconds (3000 milliseconds)
      setTimeout(() => {
        document.body.style.overflow = 'auto';
      }, 3000);
    }, 100);

    // Disable scrolling on body when the component mounts
    document.body.style.overflow = 'hidden';

    // Clean up odometer when component unmounts
    return () => {
      odometer.remove();
      // Re-enable scrolling on body when the component unmounts
      document.body.style.overflow = 'auto';
    };
  }, []);

  return (
    <div className='ordometer preloader'>
      <div className='ordometer__wrapper'>
         <p className='ordometer__text'>Loading</p>
         <div className='ordometer__block'><span ref={odometerRef} className="ordometer__value"></span></div>
      </div>
    </div>
  );
};

export default OdometerAnimation;
